#include "axyb/template_data.hpp"
#include <cstdint>
#include <fstream>
#include <stdexcept>
namespace axyb{template<class T>static void rd(std::ifstream&in,T*p,size_t n){in.read((char*)p,(std::streamsize)(sizeof(T)*n));if(!in)throw std::runtime_error("template read failed");}static std::string path(const std::string&d,int a){std::string r=d.empty()?".":d;if(r.back()!='/'&&r.back()!='\\')r+='/';return r+"AXYB_complete_x"+std::to_string(a)+".tpl";}TemplateData load_template(const std::string&dir,int action){std::ifstream in(path(dir,action),std::ios::binary);if(!in)throw std::runtime_error("cannot open template x"+std::to_string(action)+" in "+dir);char magic[8];rd(in,magic,8);if(std::string(magic,magic+8)!="AXYBTPL1")throw std::runtime_error("bad template");uint32_t h[10];rd(in,h,10);TemplateData t;t.version=h[0];t.action=h[1];t.n=h[2];t.m=h[3];uint32_t c0=h[4],c1=h[5],cc=h[6],am=h[7],tail=h[8],bc=h[9];t.tail_count=tail;t.coeff_map.resize(cc);rd(in,t.coeff_map.data(),t.coeff_map.size());t.c0_linear.resize(c0);rd(in,t.c0_linear.data(),t.c0_linear.size());t.c0_coeff.resize(c0);rd(in,t.c0_coeff.data(),t.c0_coeff.size());t.c1_linear.resize(c1);rd(in,t.c1_linear.data(),t.c1_linear.size());t.c1_coeff.resize(c1);rd(in,t.c1_coeff.data(),t.c1_coeff.size());t.am_ind.resize(am);rd(in,t.am_ind.data(),t.am_ind.size());rd(in,t.sol_sources.data(),t.sol_sources.size());std::vector<uint32_t>b(2*(size_t)bc);rd(in,b.data(),b.size());for(uint32_t i=0;i<bc;++i)t.blocks.emplace_back((int)b[2*i],(int)b[2*i+1]);return t;}std::vector<double> map_coefficients(const TemplateData&t,const std::vector<double>&data){std::vector<double>c(t.coeff_map.size());for(size_t i=0;i<c.size();++i)c[i]=data[t.coeff_map[i]];return c;}SparseMatrixCSC build_sparse_from_template(int rows,int cols,const std::vector<unsigned long long>&lin,const std::vector<unsigned int>&ci,const std::vector<double>&coeffs){std::vector<double>v(lin.size());for(size_t i=0;i<lin.size();++i)v[i]=coeffs[ci[i]];return SparseMatrixCSC::from_linear_indices(rows,cols,lin,v);} }
